import anthropic, json

client = anthropic.Anthropic()

def robust_zeroshot_json(system: str, user: str, max_retries: int = 2) -> dict | None:
    """Zero-shot call with automatic JSON repair on format failure."""
    messages = [{"role": "user", "content": user}]
    for attempt in range(max_retries + 1):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=300,
            temperature=0.0,
            system=system,
            messages=messages,
        )
        raw = resp.content[0].text.strip()
        # Strip markdown code fences if present
        if raw.startswith("```"):
            raw = "\n".join(raw.split("\n")[1:-1])
        try:
            return json.loads(raw)
        except json.JSONDecodeError:
            if attempt < max_retries:
                # Add correction turn
                messages.append({"role": "assistant", "content": raw})
                messages.append({
                    "role": "user",
                    "content": "That output is not valid JSON. Return ONLY valid JSON, no other text.",
                })
    return None  # exhausted retries


result = robust_zeroshot_json(
    system="Extract: return JSON with keys 'name' (str) and 'age' (int).",
    user="Dr. Sarah Chen, 42 years old, joined the team.",
)
print(result)  # {'name': 'Dr. Sarah Chen', 'age': 42}
